def num_squares(n: int) -> int:
    squares = []
    i = 1
    while i * i <= n:
        squares.append(i * i)
        i += 1
    INF = 10**9
    dp = [0] + [INF] * n
    for a in range(1, n + 1):
        best = INF
        for s in squares:
            if s > a:
                break
            if dp[a - s] + 1 < best:
                best = dp[a - s] + 1
        dp[a] = best
    return dp[n]

